const idNode = document.querySelector("#q-num h5 span");
const qDivNode = document.getElementById("q-div");
const oDivNode = document.getElementById("o-div");
const nDivNode = document.getElementById("n-div");
const nextNode = document.getElementById("next");
const backNode = document.getElementById("back");
const submitNode = document.getElementById("submit");
const kbdNode = document.getElementById("kbd");
const nInputNode = document.getElementById("n-input");
const saveNode = document.getElementById("save");
const saveReviewNode = document.getElementById("save-review");
const clearResponseNode = document.getElementById("clear-response");
const reviewNode = document.getElementById("review");
const reportNode = document.getElementById("report");
const secDivNode = document.getElementById("sec-div");
const menuNode = document.getElementById("menu");

const questions = /*JSON.parse(LZString.decompress(sessionStorage.getItem('questions'))) || */qns;
//console.log(questions);
const mapping = {"physics":"p", "chemistry":"c", "mathematics":"m", "mcq":"a", "numerical":"b"}
const choice = []; //it contains objects of type {id, response, time} for each question attempted/viewed by the student. response is either option number for mcq or input string for numerical type
let review = [];   //it contains ids of questions marked for review
let res;           //it stores the currently selected option for mcq type question. It is null for numerical type questions or no selected option for mcq. res means resonse.
let pDiv;          //it stores the currently selected option div for mcq type question. It is null for numerical type questions or no selected option for mcq. pDiv means previous div.
let previousSubName = "ca";
let currentq = {};  //it stores the currently displayed question object
let startTime;      //it stores the time at which the current question is displayed. It is used to calculate the time spent on each question.
let intervalId2;    //it stores the interval id for question stopwatch so that it can be cleared when question is changed.
let menuOpen = false;  //it stores the state of menu (open or closed). not in use currently.
currentq.id = "1";   //initially displaying question 1


//to start the stopwatch for the entire test duration 
function stopwatch() {
    let timer = 10800;
    let hr, min, sec;
    const timerNode = document.getElementById("timer");
    const intervalId1 = setInterval(() => {
      timer -= 1;
      sec = timer;
      min = Math.floor(timer/60);
      hr = Math.floor(min/60);
      min = min%60;
      sec = timer - (hr*60*60) - (min*60);
      try {
      const displayHr = String(hr).padStart(2, '0');
      const displayMin = String(min).padStart(2, '0');
      const displaySec = String(sec).padStart(2, '0');
      timerNode.innerText = `${displayHr}:${displayMin}:${displaySec}`;
      } catch(err) {
        console.log(err);
        clearInterval(intervalId1);
      }
      
      if (timer == 599) {timerNode.style.background = "red"}
      if (timer <= 0) {
        clearInterval(intervalId1);
      //  submit();
      }
      }, 1000);
    timerNode.innerText = `3:00:00`
}

//to start the stopwatch for each question. It takes startTimer as argument which is the time already spent on that question (in seconds) if the question is being revisited.
function qStopwatch(startTimer = 0) {
    let min, sec, min2, sec2;
    const timerNode = document.getElementById("q-timer");
    intervalId2 = setInterval(() => {
      startTimer += 1;
      sec = startTimer;
      min = Math.floor(startTimer/60);
      min = min%60;
      sec = startTimer - (min*60);
      
      try {
      const displayMin = String(min).padStart(2, '0');
      const displaySec = String(sec).padStart(2, '0');
      timerNode.innerText = `${displayMin}:${displaySec}`;
      } catch(err) {
        console.log(err);
        clearInterval(intervalId1);
      }
      }, 1000);
      
    sec2 = startTimer;
    min2 = Math.floor(startTimer/60);
    min2 = min2%60;
    sec2 = startTimer - (min2*60);
    const displayMin2 = String(min2).padStart(2, '0');
    const displaySec2 = String(sec2).padStart(2, '0');
    timerNode.innerText = `${displayMin2}:${displaySec2}`;
}

function kbdfn() {
  [...kbdNode.querySelectorAll("button")].forEach((e) => {
    e.addEventListener("click", () => keyboardinput(e.id));
  })
}

function keyboardinput(id) {
  if (id == "bb") {
    nInputNode.innerText = nInputNode.innerText.slice(0,-1);
  } else if (id == "bc") {
    nInputNode.innerText = "";
  } else {
    nInputNode.innerText += id.slice(-1);
  }
}

function displayQuestion(i) {
  const q = questions.find(e => e.id == i);
  currentq = q;
  idNode.innerText = q.id;
  qDivNode.innerHTML = q.question;
  startTime = Date.now();
  const p = choice.find(e => e.id == q.id);
  
  if (q.type == "mcq") {
    nDivNode.style.display = "none";
    oDivNode.style.display = "";
    console.log([...oDivNode.querySelectorAll("p")]);
    console.log("pDiv:", pDiv);
    [...oDivNode.querySelectorAll("p")].forEach((e, index) => {e.innerHTML = `${index}: ${q.options[index]}`; console.log(index, ":", q.options[index]);});
    if (p && [0,1,2,3].includes(p.response)) {
      res = p.response;
      oDivNode.children[p.response].click();
    } else {
      res = null;
      if (pDiv) pDiv.classList.remove("clicked");
      pDiv = null;
    }
  } else {
    oDivNode.style.display = "none";
    nDivNode.style.display = "";
    if (p) {
      nInputNode.innerText = p.response !== null ? p.response : "";
    } else {
      nInputNode.innerText = "";
    }
  }
  
  clearInterval(intervalId2);
  if (p) {
    qStopwatch(p.time);
  } else {
    qStopwatch(0);
  }
  
  const subName = `${mapping[q.subject]}${mapping[q.type]}`;
  
  if (subName !== previousSubName) {
    document.getElementById(previousSubName).classList.remove("active");
    document.getElementById(subName).classList.add("active");
    previousSubName = subName;
  }
  
  MENU.toggleCurrentClass(currentq.id);

  if (q.id == questions.length) {
    nextNode.disabled = true;
  } else {
    nextNode.disabled = false;
  }
  
  if (q.id == 1) {
    backNode.disabled = true;
  } else {
    backNode.disabled = false;
  }
}

function save() {
  const q = choice.find(e => e.id == currentq.id);
  let responseValue = null;
  
  if (currentq.type === "mcq") {
    responseValue = res;
  } else {
    const raw = nInputNode.innerText.trim();
    responseValue = raw === "" ? null : Number(raw);
  }
  
  if (q) {
    q.response = responseValue;
  } else {
    choice.push({
      id: currentq.id,
      response: responseValue,
      time: 0
    })
  }
}

function updateTime() {
  const q = choice.find(e => e.id == currentq.id);
  if (q) {
    q.time += parseInt((Date.now() - startTime)/1000);
  } else {
    choice.push({
      id: currentq.id,
      response: null,
      time: parseInt((Date.now() - startTime)/1000)
    })
  }

  MENU.toggleCurrentClass(currentq.id);
  if (window.matchMedia("screen and (min-width: 200px)").matches) MENU.updateQuestionBox(currentq.id);
}

