const MENU = {
  isOpen: false,

  toggle: function() {
    if (window.matchMedia("screen and (min-width: 200px)").matches) return;
    if (this.isOpen == true) {
      this.close();
    } else {
      this.open();
    }
  },

  close: function() {
    menuNode.innerText = "⟨";
    secDivNode.style.animation = "slideRight 0.3s ease-in-out";
    window.removeEventListener("keydown", MENU._handleMenuEscape);
    window.removeEventListener("click", MENU._handleOutsideMenuClick);
    setTimeout(() => {
     secDivNode.style.display = "none";
      this.isOpen = false;
    }, 300);
  },

  open: function() {
    secDivNode.style.animation = "slideLeft 0.3s ease-in-out";
    secDivNode.style.display = "block";
    menuNode.innerText = "⟩";
    window.addEventListener("click", MENU._handleOutsideMenuClick);
    window.addEventListener("keydown", MENU._handleMenuEscape);
    
    this.isOpen = true;
    if (!questions) return;
    this.createQuestionBoxes();
  },

  _getQuestionStates: function() {
    const ans = [];
    const nans = [];
    
    choice.forEach(e => {
      if (e.response !== null) {
        ans.push(e.id);
      } else {
        nans.push(e.id);
      }
    });

    const ansr = ans.filter(e => review.includes(e));

    return { ans, nans, ansr };
  },

  _getClassName: function(qId, ans, nans, ansr) {
    if (ansr.includes(qId)) return "amfr";
    if (ans.includes(qId)) return "a";
    if (review.includes(qId)) return "mfr";
    if (nans.includes(qId)) return "na";
    return "nv";
  },

  _updateSummaryCounts: function(ans, ansr) {
    document.getElementById("a").innerText = ans.length;
    document.getElementById("na").innerText = (questions.length - ans.length);
    document.getElementById("nv").innerText = (questions.length - choice.length);
    document.getElementById("mfr").innerText = (review.length - ansr.length);
    document.getElementById("amfr").innerText = ansr.length;
  },

  createQuestionBoxes: function() {
    const len = questions.length;
    let el = "";
    const { ans, nans, ansr } = this._getQuestionStates();

    for (let i = 1; i <= len; i++) {
      let class2 = this._getClassName(i, ans, nans, ansr);
      el += `<div class="num-box ${class2}" onclick="updateTime(); displayQuestion(${i}); document.getElementById('menu').click();" title="${i}">${i}</div>`;
    }
    
    document.getElementById("sec2").innerHTML = el;
    this._updateSummaryCounts(ans, ansr);
  },

  updateQuestionBox: function(qId) {
    const box = document.querySelector(`#sec2 div[title="${qId}"]`);
    const { ans, nans, ansr } = this._getQuestionStates();
    let class2 = this._getClassName(qId, ans, nans, ansr);

    box.outerHTML = `<div class="num-box ${class2}" onclick="updateTime(); displayQuestion(${qId}); document.getElementById('menu').click();" title="${qId}">${qId}</div>`;
    this._updateSummaryCounts(ans, ansr);
  },

  _handleOutsideMenuClick: function(e) {
    if (e.target !== secDivNode && e.target !== menuNode) {
      document.getElementById("menu").click();
    }
  },

  _handleMenuEscape: function(e) {
    if (e.target !== secDivNode && e.target !== menuNode) {
      document.getElementById("menu").click();
    }
  },

  toggleCurrentClass: function(id) {document.querySelector(`#sec2 div[title="${id}"]`)?.classList.toggle('current')}
};

function getSubjectInitial() {
  const ma = questions.find(e => (e.subject == "mathematics" && e.type == "mcq"))?.id;
  const mb = questions.find(e => (e.subject == "mathematics" && e.type == "numerical"))?.id;
  const pa = questions.find(e => (e.subject == "physics" && e.type == "mcq"))?.id;
  const pb = questions.find(e => (e.subject == "physics" && e.type == "numerical"))?.id;
  const ca = questions.find(e => (e.subject == "chemistry" && e.type == "mcq"))?.id;
  const cb = questions.find(e => (e.subject == "chemistry" && e.type == "numerical"))?.id;
  
  Object.entries({ ma, mb, pa, pb, ca, cb }).forEach(([name, value]) => {
    document.getElementById(name)?.addEventListener("click", () => {
      updateTime();
      displayQuestion(value);
    });
  });
}

function getTestName() {
  const MONTH = ["Jan", "Feb", "March", "April", "May", "June", "July", "Aug", "Sep", "Oct", "Nov", "Dec"];
  const EXAM_LIST = {"jm": "JEE Mains", "ja": "JEE Advanced", "n": "NEET"};
  const EXAM = window.location.hash.substring(1) || "jm2026040802";
  let name = "";
  EXAM.match(/\D/g).forEach((e) => name += e);
  for (let a in EXAM_LIST) { if (a == name) name = EXAM_LIST[a]};
  let year = EXAM.slice(-10, -6);
  let month = MONTH[Number(EXAM.slice(-6, -4)) + 1];
  const EXAM_NAME = `${name} ${EXAM.slice(-4,-2)} ${month} ${year} Shift-${EXAM.slice(-2)}`;
  return EXAM_NAME;
}

getSubjectInitial();

document.getElementById("test-name").innerText = getTestName();
